namespace Lof\Formbuilder\Controller\Adminhtml;

use Magento\Backend\App\Action;
use Magento\Backend\App\Action\Context;
use Magento\Backend\Model\View\Result\Page;
use Magento\Framework\Registry;

abstract class Blacklist extends Action
{
    public const ADMIN_RESOURCE = 'Lof_Formbuilder::blacklist';
    /**
     * Core registry
     *
     * @var Registry|null
     */
    protected $coreRegistry = null;

    /**
     * @param Context $context
     * @param Registry $coreRegistry
     */
    public function __construct(Context $context, Registry $coreRegistry)
    {
        $this->coreRegistry = $coreRegistry;
        parent::__construct($context);
    }

    /**
     * Init page
     *
     * @param Page $resultPage
     * @return Page
     */
    protected function initPage($resultPage)
    {
        $resultPage->setActiveMenu('Lof_Formbuilder::form')
            ->addBreadcrumb(__('FormBuilder'), __('FormBuilder'))
            ->addBreadcrumb(__('Form'), __('Blacklist'));
        return $resultPage;
    }
}
